#include<bits/stdc++.h>
using namespace std;
int flag[101][101][101],f[101][101];
int main()
{
    int n,m;
    scanf("%d%d",&n,&m);
    memset(f,0x3f,sizeof(f));
    for(int i=1;i<=m;i++)
    {
        int u,v;
        scanf("%d%d",&u,&v);
        flag[u][v][0]=f[u][v]=1;
    }
    for(int b=1;b<=64;b++)
    {
        for(int k=1;k<=n;k++)
        {
            for(int i=1;i<=n;i++)
            {
                for(int j=1;j<=n;j++)
                {
                    if(flag[i][k][b-1]&&flag[k][j][b-1])
                    {
                        f[i][j]=flag[i][j][b]=1;
                    }
                }
            }
        }
    }
    for(int k=1;k<=n;k++)
    {
        for(int i=1;i<=n;i++)
        {
            for(int j=1;j<=n;j++)
            {
                f[i][j]=min(f[i][j],f[i][k]+f[k][j]);
            }
        }
    }
    printf("%d",f[1][n]);
    return 0;
}
